#include<bits/stdc++.h>
#define pre(i, l, r)	for(int i = (l); i <= (r); ++i)
#define fpre(i, r, l)	for(int i = (r); i >= (l); --i)
#define ll long long

using namespace std;

const int maxn = 1e6 + 5;
const int inf = 1e9;

template<typename T>inline void S(T& x){x = 0;int f = 0;char ch = getchar();while(!isdigit(ch))	f |= (ch == '-'), ch = getchar();
while(isdigit(ch))	x = x * 10 + (ch ^ 48), ch = getchar();if(f) x = -x;}
template<typename T,typename...type>inline void S(T& x, type&...y)	{S(x);S(y...);}

string s, t;
int n, m;
complex<double> a[maxn], b[maxn];
int res[maxn];
const double pi = acos(-1.);

inline void FFT(complex<double>* a, int n, int f)
{
	pre(i, 0, n - 1)
	{
		res[i] = (res[i >> 1] >> 1);
		if(i & 1)	res[i] |= (n >> 1);
	}
	pre(i, 0, n - 1)
		if(i < res[i])
			swap(a[i], a[res[i]]);
	for(int len = 2; len <= n; len <<= 1)
	{
		complex<double> wn(cos(2 * pi / len), f * sin(2 * pi / len));
		for(int i = 0; i < n; i += len)
		{
			complex<double> w(1,0);
			for(int j = i; j < i + len / 2; j++)
			{
				complex<double> l = a[j], r = a[j + len / 2];
				a[j] = l + w * r;
				a[j + len / 2] = l - w * r;
				w *= wn;
			}
		}
	}
	if(f == -1)
		pre(i, 0, n - 1)
			a[i] /= n;
}

int main()
{
	cin>>s>>t;
	n = s.size(), m = t.size();
	pre(i, 0, n - 1)
		a[n - i - 1] = (double)(s[i] ^ 48);
	pre(i, 0, m - 1)
		b[m - i - 1] = (double)(t[i] ^ 48);
	int l = 1;
	while(l < n + m)	l *= 2;
	FFT(a, l, 1);
	FFT(b, l, 1);
	pre(i, 0, l - 1)
		a[i] *= b[i]; 
	FFT(a, l, -1);
	pre(i, 0, l - 1)
		a[i + 1] += (int)(a[i].real() + 0.5) / 10;
	while((int)(a[l].real() + 0.5) <= 0)	--l;
	if(!l)
		return puts("0"), 0;
	fpre(i, l, 0)
		printf("%d", (int)(a[i].real() + 0.5) % 10);
	return 0;
}
